// // This module resets the flip-flop on every negative edge of the clock and toggles it on every positive edge
module toggle_flip_flop (
    input clk,
    input reset,
    output reg q
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            q <= 0;
        end else begin
            q <= ~q;
        end
    end
endmodule
